const items = $input.all().map(item => item.json);
return [{
  json: {
    fileContent: `Health check OK. Con ${items.length} task dang mo luc cuoi ngay.`
  }
}];

const items = $input.all().map(item => item.json);

let text = 'Bao cao task qua han tu dong:\n';
if (!items.length) {
  text += '- Khong co task qua han.';
} else {
  for (const task of items) {
    text += `- ${task.taskId}: ${task.taskName} | ${task.assigneeEmail} | deadline ${task.deadline}\n`;
  }
}

return [{
  json: {
    report: text,
    count: items.length,
    tasks: items
  }
}];

const parseDate = (value) => {
  if (!value) return null;

  if (Array.isArray(value)) {
    const [year, month = 1, day = 1, hour = 0, minute = 0, second = 0, nano = 0] = value;
    const millis = Math.floor(Number(nano) / 1000000);
    const date = new Date(year, month - 1, day, hour, minute, second, millis);
    return Number.isNaN(date.getTime()) ? null : date;
  }

  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
};

const formatDate = (value) => {
  const date = parseDate(value);
  if (!date) return null;

  const pad = (input) => String(input).padStart(2, '0');
  return `${pad(date.getDate())}/${pad(date.getMonth() + 1)}/${date.getFullYear()} ${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

const now = new Date();

return $input.all().map((entry) => {
  const item = entry.json ?? {};
  const deadline = parseDate(item.deadline);
  const daysLeft = deadline ? Math.ceil((deadline.getTime() - now.getTime()) / 86400000) : null;

  return {
    json: {
      ...item,
      deadline: deadline?.toISOString() ?? item.deadline ?? null,
      deadlineDisplay: item.deadlineDisplay ?? formatDate(item.deadline) ?? 'Chua co deadline',
      daysLeft
    }
  };
});

const parseDate = (value) => {
  if (!value) return null;

  if (Array.isArray(value)) {
    const [year, month = 1, day = 1, hour = 0, minute = 0, second = 0, nano = 0] = value;
    const millis = Math.floor(Number(nano) / 1000000);
    const date = new Date(year, month - 1, day, hour, minute, second, millis);
    return Number.isNaN(date.getTime()) ? null : date;
  }

  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
};

const formatDate = (value) => {
  const date = parseDate(value);
  if (!date) return null;

  const pad = (input) => String(input).padStart(2, '0');
  return `${pad(date.getDate())}/${pad(date.getMonth() + 1)}/${date.getFullYear()} ${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

const deadline = parseDate($json.deadline);
const completedAt = parseDate($json.completedAt) ?? new Date();
const isEarly = deadline ? completedAt.getTime() <= deadline.getTime() : false;

return [{
  json: {
    ...$json,
    deadline: deadline?.toISOString() ?? $json.deadline ?? null,
    deadlineDisplay: $json.deadlineDisplay ?? formatDate($json.deadline) ?? 'Chua co deadline',
    completedAt: completedAt.toISOString(),
    completedAtDisplay: formatDate(completedAt),
    isEarly
  }
}];

const body = $json.body ?? $json;

const parseDate = (value) => {
  if (!value) return null;

  if (Array.isArray(value)) {
    const [year, month = 1, day = 1, hour = 0, minute = 0, second = 0, nano = 0] = value;
    const millis = Math.floor(Number(nano) / 1000000);
    const date = new Date(year, month - 1, day, hour, minute, second, millis);
    return Number.isNaN(date.getTime()) ? null : date;
  }

  if (typeof value === 'object') {
    const date = new Date(value);
    return Number.isNaN(date.getTime()) ? null : date;
  }

  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
};

const formatDate = (value) => {
  const date = parseDate(value);
  if (!date) return null;

  const pad = (input) => String(input).padStart(2, '0');
  return `${pad(date.getDate())}/${pad(date.getMonth() + 1)}/${date.getFullYear()} ${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

const deadlineRaw = body.deadline ?? body.dueDate ?? body.endDate;
const description = body.taskDescription ?? body.adminNote ?? body.sourceInput ?? body.description ?? null;
const note = body.adminNote ?? body.sourceInput ?? body.taskDescription ?? null;
const deadlineDate = parseDate(deadlineRaw);
const completedDate = parseDate(body.completedAt);
const createdDate = parseDate(body.createdAt);

return [{
  json: {
    taskId: body.taskId,
    taskName: body.taskName,
    taskDescription: description,
    adminNote: body.adminNote ?? null,
    sourceInput: body.sourceInput ?? null,
    assigneeEmail: body.assigneeEmail,
    managerEmail: body.managerEmail,
    ownerName: body.ownerName,
    priority: body.priority,
    status: body.status,
    eventType: body.eventType ?? null,
    eventMessage: body.eventMessage ?? null,
    deadline: deadlineDate?.toISOString() ?? deadlineRaw ?? null,
    deadlineDisplay: formatDate(deadlineRaw) ?? (typeof deadlineRaw === 'string' ? deadlineRaw : null) ?? 'Chưa có deadline',
    createdAt: createdDate?.toISOString() ?? body.createdAt ?? null,
    createdAtDisplay: formatDate(body.createdAt),
    completedAt: completedDate?.toISOString() ?? null,
    completedAtDisplay: formatDate(body.completedAt),
    reminderCount: body.reminderCount ?? 0,
    note,
    receivedAt: new Date().toISOString()
  }
}];

return $input.all().map((entry) => {
  const item = entry.json ?? {};
  return {
    json: {
      ...item,
      taskId: item.taskId ?? 'UNKNOWN',
      taskName: item.taskName ?? 'Untitled task',
      assigneeEmail: item.assigneeEmail ?? null,
      priority: item.priority ?? 'MEDIUM',
      status: item.status ?? 'PENDING',
      deadline: item.deadline ?? null,
      daysLeft: item.daysLeft ?? null,
      reminderCount: item.reminderCount ?? 0,
    }
  };
});

return [{
  json: {
    ...$json,
    opsMessage: [
      'THONG BAO NHAC VIEC',
      `Task: ${$json.taskName || '-'}`,
      `Ma task: ${$json.taskId || '-'}`,
      `Nguoi duoc giao: ${$json.assigneeEmail || '-'}`,
      `Con lai: ${$json.daysLeft ?? 'NA'} ngay`,
      `Deadline: ${$json.deadlineDisplay || $json.deadline || '-'}`
    ].join('\n')
  }
}];

return [{
  json: {
    ...$json,
    opsMessage: [
      'BAO CAO QUA HAN',
      `Task: ${$json.taskName || '-'}`,
      `Ma task: ${$json.taskId || '-'}`,
      `Nguoi duoc giao: ${$json.assigneeEmail || '-'}`,
      `Deadline: ${$json.deadlineDisplay || $json.deadline || '-'}`
    ].join('\n')
  }
}];

const items=$input.all().map(i=>i.json);
const high=items.filter(i=>i.priority==='HIGH').length;
const inProgress=items.filter(i=>i.status==='IN_PROGRESS').length;
return [{json:{items,totalOpen:items.length,highPriorityCount:high,inProgressCount:inProgress,snapshotAt:new Date().toISOString()}}];

return [{
  json: {
    ...$json,
    opsMessage: [
      'BAO CAO HE THONG CUOI NGAY',
      `Tong task dang mo: ${$json.totalOpen ?? '-'}`,
      `Task uu tien cao: ${$json.highPriorityCount ?? '-'}`,
      `Task dang xu ly: ${$json.inProgressCount ?? '-'}`,
      `Thoi diem chup: ${$json.snapshotAt || '-'}`
    ].join('\n')
  }
}];
